module RefModule(
  input clk,
  input reset_n,
  output [3:0] count
);reg [3:0] obf_counter = 4'd0;

  always @(posedge clk, negedge reset_n) begin
    if (!reset_n) begin
      obf_counter <= 4'd0;
    end else if (obf_counter == 4'd9) begin
      obf_counter <= 4'd0;
    end else begin
      obf_counter <= obf_counter + 1;
    end
  end

  assign count = obf_counter;

endmodule
